fn is_balanced(n: i64, codes: i64) -> i64 = {
    if n == 0 { return 1 };

    let stack = vec_new();
    let i = 0;
    let balanced = 1;

    while i < n {
        let c = vec_get(codes, i);
        i = i + 1;

        if c == 40 || c == 91 || c == 123 {
            let _p = vec_push(stack, c);
        } else if c == 41 || c == 93 || c == 125 {
            let len = vec_len(stack);
            if len == 0 {
                return 0;
            }
            let top = vec_get(stack, len - 1);
            let _pop = vec_pop(stack);

            if c == 41 && top != 40 { return 0; }
            if c == 93 && top != 91 { return 0; }
            if c == 125 && top != 123 { return 0; }
        }
    };

    if vec_len(stack) == 0 { 1 } else { 0 }
};

fn main() -> i64 = {
    let t = read_int();
    let mut tc = 0;
    while tc < t {
        let n = read_int();
        let codes = vec_new();
        let j = 0;
        while j < n {
            let val = read_int();
            let _p = vec_push(codes, val);
            j = j + 1;
        };

        let result = is_balanced(n, codes);
        let _p = println(result);

        let _f = vec_free(codes);
        tc = tc + 1;
    };
    0
};

